// ========== 状态 ==========
let currentAuthors = []; // 当前筛选后的作者列表
let currentAuthor = null; // 当前选中的作者
let currentSearch = ''; // 当前搜索关键词
let currentRegion = 'all'; // 当前区域筛选
let currentEra = 'all'; // 当前时代筛选
let currentCategory = 'all'; // 当前分类筛选

// ========== DOM 元素 ==========
const authorList = document.getElementById('authorList');
const authorDetail = document.getElementById('authorDetail');
const searchInput = document.getElementById('searchInput');
const regionFilter = document.getElementById('regionFilter');
const eraFilter = document.getElementById('eraFilter');
const categoryFilter = document.getElementById('categoryFilter');

// ========== 初始化 ==========
function init() {
  currentAuthors = [...authors];
  renderAuthorList();
  setupEventListeners();
  // 默认显示第一位作者
  if (currentAuthors.length > 0) {
    selectAuthor(currentAuthors[0].id);
  }
}

// ========== 事件监听 ==========
function setupEventListeners() {
  searchInput.addEventListener('input', debounce(handleSearch, 300));
  regionFilter.addEventListener('change', handleFilter);
  eraFilter.addEventListener('change', handleFilter);
  categoryFilter.addEventListener('change', handleFilter);
}

// ========== 标签页切换 ==========
const tabBtns = document.querySelectorAll('.tab-btn');
const tabContents = document.querySelectorAll('.tab-content');
const workspaceBadge = document.getElementById('workspaceBadge');
const workspaceStatus = document.getElementById('workspaceStatus');

function switchToTab(tabName) {
  tabBtns.forEach(b => b.classList.remove('active'));
  tabContents.forEach(c => c.classList.remove('active'));
  document.querySelector('.tab-btn[data-tab="' + tabName + '"]').classList.add('active');
  document.getElementById('tab' + (tabName === 'detail' ? 'Detail' : 'Workspace')).classList.add('active');
}

tabBtns.forEach(btn => {
  btn.addEventListener('click', () => {
    switchToTab(btn.dataset.tab);
  });
});

function signalWorkspaceActivity() {
  workspaceBadge.style.display = 'inline';
  workspaceStatus.textContent = 'AI 正在生成...';
}
function clearWorkspaceSignal() {
  workspaceBadge.style.display = 'none';
  if (currentAiInstruction) {
    workspaceStatus.textContent = '当前指令：' + currentAiInstruction.authorName + '（' + currentAiInstruction.content.length + '字）';
  } else {
    workspaceStatus.textContent = '就绪 — 请先在作者详情中点击「AI 生成指令」';
  }
}

// ========== 搜索处理 ==========
function handleSearch(e) {
  currentSearch = e.target.value.trim().toLowerCase();
  applyFilters();
}

// ========== 筛选处理 ==========
function handleFilter() {
  currentRegion = regionFilter.value;
  currentEra = eraFilter.value;
  currentCategory = categoryFilter.value;
  applyFilters();
}

// ========== 应用筛选 ==========
function applyFilters() {
  currentAuthors = authors.filter(author => {
    // 搜索过滤
    if (currentSearch) {
      const searchStr = (author.name + author.nameEn + author.style + author.characteristics).toLowerCase();
      if (!searchStr.includes(currentSearch)) return false;
    }
    // 区域过滤
    if (currentRegion !== 'all' && author.region !== currentRegion) return false;
    // 时代过滤
    if (currentEra !== 'all' && author.era !== currentEra) return false;
    // 分类过滤：文学作家没有 category 字段，用 undefined 匹配
    if (currentCategory !== 'all') {
      if (currentCategory === '文学作家') {
        if (author.category) return false;
      } else if (author.category !== currentCategory) {
        return false;
      }
    }
    return true;
  });
  renderAuthorList();
  // 如果当前选中的作者不在筛选结果中，清除详情
  if (currentAuthor && !currentAuthors.find(a => a.id === currentAuthor.id)) {
    currentAuthor = null;
    authorDetail.innerHTML = '<div class="empty-state"><div class="empty-icon">📖</div><p>请从左侧列表选择一位作家</p></div>';
  }
}

// ========== 渲染作者列表 ==========
function renderAuthorList() {
  if (currentAuthors.length === 0) {
    authorList.innerHTML = '<div class="empty-state"><div class="empty-icon">🔍</div><p>未找到匹配的作家</p></div>';
    return;
  }
  authorList.innerHTML = currentAuthors.map(author => `
    <div class="author-item ${currentAuthor && currentAuthor.id === author.id ? 'active' : ''}" data-id="${author.id}" onclick="selectAuthor('${author.id}')">
      <div class="author-name">${author.name}</div>
      <div class="author-meta">${author.nameEn} · ${author.region} · ${author.era}</div>
    </div>
  `).join('');
}

// ========== 选择作者 ==========
function selectAuthor(id) {
  currentAuthor = currentAuthors.find(a => a.id === id) || authors.find(a => a.id === id);
  if (!currentAuthor) return;
  // 更新列表高亮
  document.querySelectorAll('.author-item').forEach(item => {
    item.classList.toggle('active', item.dataset.id === id);
  });
  // 渲染详情
  renderAuthorDetail();
  // 移动端滚动到详情
  if (window.innerWidth <= 768) {
    authorDetail.scrollIntoView({ behavior: 'smooth' });
  }
}

// ========== 渲染作者详情 ==========
function renderAuthorDetail() {
  if (!currentAuthor) return;
  const chars = currentAuthor.characteristics.split('；').filter(c => c.trim());
  const categoryLabel = currentAuthor.category ? `<span class="tag tag-category">${currentAuthor.category}</span>` : '';
  authorDetail.innerHTML = `
    <div class="detail-header">
      <h2 class="detail-name">${currentAuthor.name} <span class="detail-name-en">${currentAuthor.nameEn}</span></h2>
      <div class="detail-tags">
        <span class="tag tag-region">${currentAuthor.region}</span>
        <span class="tag tag-era">${currentAuthor.era}</span>
        ${categoryLabel}
      </div>
    </div>
    <div class="detail-section">
      <h3 class="section-title">风格概述</h3>
      <p class="style-desc">${currentAuthor.style}</p>
    </div>
    <div class="detail-section">
      <h3 class="section-title">写作特征</h3>
      <ul class="characteristics-list">
        ${chars.map(c => `<li>${c.trim()}</li>`).join('')}
      </ul>
    </div>
    <div class="detail-section">
      <h3 class="section-title">经典片段</h3>
      <blockquote class="example-blockquote">
        <p>${currentAuthor.example}</p>
        <footer>—— ${currentAuthor.exampleSource}</footer>
      </blockquote>
    </div>
    <div class="detail-section">
      <h3 class="section-title">写作禁忌</h3>
      <div class="avoid-list">
        ${currentAuthor.avoid.split('、').map(a => `<span class="avoid-tag">${a.trim()}</span>`).join('')}
      </div>
    </div>
  `;
}

// ========== 防抖函数 ==========
function debounce(fn, delay) {
  let timer;
  return function(...args) {
    clearTimeout(timer);
    timer = setTimeout(() => fn.apply(this, args), delay);
  };
}

// ========== Toast ==========
function showToast(msg) {
  const toast = document.getElementById('toast');
  if (!toast) return;
  toast.textContent = msg;
  toast.classList.add('show');
  clearTimeout(toast._t);
  toast._t = setTimeout(() => toast.classList.remove('show'), 2000);
}

